Hey, I am seeing a performance drop in `psa_asymmetric_encrypt()/psa_asymmetric_decrypt()` after updating to mbedTLS v4.1.0.

It seems that `mbedtls_rsa_check_privkey()` was added to `mbedtls_rsa_parse_key()` in 4.1.0 (not present in 4.0.0). Since `mbedtls_psa_rsa_load_representation()` calls `mbedtls_rsa_parse_key()` on every `psa_asymmetric_encrypt()` / `psa_asymmetric_decrypt()` call — PSA does not cache the parsed RSA context — this expensive validation runs on every operation, not just once at import time.

As the key is already validated during `psa_import_key()` → `mbedtls_psa_rsa_import_key()`, is this per-operation check redundant?

### System information

Mbed TLS version (number or commit id): 4.1.0
Operating system and version: macOS / ESP-IDF
Configuration (if not default, please attach `mbedtls_config.h`): Default
Compiler and options (if you used a pre-built binary, please indicate how you obtained it): cc -O2
Additional environment information: 

### Expected behavior
Similar RSA performance between v4.0.0 and v4.1.0


### Actual behavior
## Performance Impact

### Host benchmark (macOS, Apple M-series, -O2, software-only, clean upstream builds)

| Operation | 4.0.0 | 4.1.0 | Regression |
|---|---|---|---|
| RSA-2048 Encrypt | 561 us | 692 us | **+23%** |
| RSA-2048 Decrypt | 15,981 us | 12,730 us | -20% (improved by CRT blinding changes) |
| RSA-4096 Encrypt | 1,440 us | 1,894 us | **+32%** |
| RSA-4096 Decrypt | 64,615 us | 49,033 us | -24% (improved by CRT blinding changes) |

The performance difference might be higher on constraint devices, I tested with ESP32-S3

### ESP32-S3 benchmark (hardware MPI acceleration, same sdkconfig)

| Operation | 4.0.0 | 4.1.0 | 4.1.0 (check_privkey removed) |
|---|---|---|---|
| RSA-2048 Encrypt | 23,994 us | 44,485 us (**1.85x**) | 23,835 us |
| RSA-2048 Decrypt | 603,137 us | 646,268 us (+7%) | 623,540 us |
| RSA-4096 Encrypt | 85,727 us | 173,001 us (**2.02x**) | 85,670 us |
| RSA-4096 Decrypt | 3,017,480 us | 3,155,968 us (+5%) | 3,068,307 us |

On ESP32-S3, `check_privkey` causes a **~2x regression on public key operations**. Removing it restores performance to 4.0.0 levels.


### Steps to reproduce
### Benchmark code (`rsa_bench.c`)

```c
#include <stdio.h>
#include <string.h>
#include <time.h>
#include "psa/crypto.h"

static long long time_us(void)
{
    struct timespec ts;
    clock_gettime(CLOCK_MONOTONIC, &ts);
    return (long long)ts.tv_sec * 1000000LL + ts.tv_nsec / 1000;
}

static int bench_rsa(size_t key_bits, int iterations)
{
    psa_status_t status;
    psa_key_id_t key_id = 0;
    psa_key_attributes_t attributes = PSA_KEY_ATTRIBUTES_INIT;

    psa_set_key_type(&attributes, PSA_KEY_TYPE_RSA_KEY_PAIR);
    psa_set_key_algorithm(&attributes, PSA_ALG_RSA_PKCS1V15_CRYPT);
    psa_set_key_usage_flags(&attributes,
                            PSA_KEY_USAGE_ENCRYPT | PSA_KEY_USAGE_DECRYPT);
    psa_set_key_bits(&attributes, key_bits);

    printf("Generating RSA-%zu key...\n", key_bits);
    status = psa_generate_key(&attributes, &key_id);
    if (status != PSA_SUCCESS) {
        printf("Key generation failed: %d\n", (int)status);
        return -1;
    }

    uint8_t plaintext[] = "Test message for RSA encryption";
    size_t plaintext_len = sizeof(plaintext);
    size_t ct_size = key_bits / 8;
    uint8_t ciphertext[512];
    uint8_t decrypted[512];
    size_t enc_len = 0, dec_len = 0;

    /* Warmup */
    psa_asymmetric_encrypt(key_id, PSA_ALG_RSA_PKCS1V15_CRYPT,
                           plaintext, plaintext_len, NULL, 0,
                           ciphertext, ct_size, &enc_len);

    /* Benchmark encrypt (public op) */
    long long total_enc = 0;
    for (int i = 0; i < iterations; i++) {
        long long t = time_us();
        status = psa_asymmetric_encrypt(key_id, PSA_ALG_RSA_PKCS1V15_CRYPT,
                                        plaintext, plaintext_len, NULL, 0,
                                        ciphertext, ct_size, &enc_len);
        total_enc += time_us() - t;
        if (status != PSA_SUCCESS) return -1;
    }

    /* Benchmark decrypt (private op) */
    long long total_dec = 0;
    for (int i = 0; i < iterations; i++) {
        psa_asymmetric_encrypt(key_id, PSA_ALG_RSA_PKCS1V15_CRYPT,
                               plaintext, plaintext_len, NULL, 0,
                               ciphertext, ct_size, &enc_len);
        long long t = time_us();
        status = psa_asymmetric_decrypt(key_id, PSA_ALG_RSA_PKCS1V15_CRYPT,
                                        ciphertext, enc_len, NULL, 0,
                                        decrypted, sizeof(decrypted), &dec_len);
        total_dec += time_us() - t;
        if (status != PSA_SUCCESS) return -1;
    }

    printf("[RSA-%zu] PUBLIC_OP  avg: %lld us (%d iterations)\n",
           key_bits, total_enc / iterations, iterations);
    printf("[RSA-%zu] PRIVATE_OP avg: %lld us (%d iterations)\n",
           key_bits, total_dec / iterations, iterations);

    psa_destroy_key(key_id);
    return 0;
}

int main(void)
{
    if (psa_crypto_init() != PSA_SUCCESS) return 1;
    printf("=== RSA PSA Benchmark ===\n\n");
    bench_rsa(2048, 5);
    printf("\n");
    bench_rsa(4096, 3);
    return 0;
}
```


